import * as React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { LucideIcon, Menu, X, ArrowRight, Wheat, CheckCircle2 } from 'lucide-react';
import { cn } from '@/lib/utils';

// --- Types & Constants ---

interface NavLink {
  label: string;
  href: string;
}
interface CurriculumRow {
  time: string;
  module: string;
  hydration: string;
  temp: string;
}
interface CurriculumDay {
  number: string;
  title: string;
  description: string;
  rows: CurriculumRow[];
}
const NAV_LINKS: NavLink[] = [{
  label: 'CURRICULUM',
  href: '#curriculum'
}, {
  label: 'INSTRUCTORS',
  href: '#instructors'
}, {
  label: 'APPLY',
  href: '#apply'
}];
const CURRICULUM_DATA: CurriculumDay[] = [{
  number: '01',
  title: 'DAY 01 — FOUNDATIONS',
  description: 'Mastering the elementary physics of water, flour, and salt. Understanding the microbiology of a wild yeast starter from the cellular level up.',
  rows: [{
    time: '9:00 AM',
    module: 'Sourdough Starter Science',
    hydration: '68%',
    temp: '24°C'
  }, {
    time: '11:00 AM',
    module: 'Flour Selection & Hydration',
    hydration: '72%',
    temp: '22°C'
  }, {
    time: '2:00 PM',
    module: 'Fermentation Fundamentals',
    hydration: '75%',
    temp: '26°C'
  }, {
    time: '4:00 PM',
    module: 'Shaping & Scoring',
    hydration: '78%',
    temp: '25°C'
  }]
}, {
  number: '02',
  title: 'DAY 02 — ADVANCED TECHNIQUE',
  description: 'Pushing the limits of hydration. We explore enriched doughs, lamination, and the violent thermal dynamics of the wood-fired hearth.',
  rows: [{
    time: '9:00 AM',
    module: 'Enriched Doughs & Brioche',
    hydration: '65%',
    temp: '28°C'
  }, {
    time: '11:00 AM',
    module: 'Laminated Pastry',
    hydration: '60%',
    temp: '18°C'
  }, {
    time: '2:00 PM',
    module: 'Oven Dynamics & Steam',
    hydration: '80%',
    temp: '240°C'
  }, {
    time: '4:00 PM',
    module: 'Crust Colour & Texture',
    hydration: '76%',
    temp: '230°C'
  }]
}, {
  number: '03',
  title: 'DAY 03 — MASTERY',
  description: 'Synthesizing knowledge into professional-grade menu development. Final critiques and the chemistry of complex flavour profiles.',
  rows: [{
    time: '9:00 AM',
    module: 'Regional Bread Traditions',
    hydration: '74%',
    temp: '25°C'
  }, {
    time: '11:00 AM',
    module: 'Menu Development',
    hydration: '70%',
    temp: '23°C'
  }, {
    time: '2:00 PM',
    module: 'Live Critique & Feedback',
    hydration: '78%',
    temp: '25°C'
  }, {
    time: '4:00 PM',
    module: 'Final Showcase',
    hydration: '76%',
    temp: '235°C'
  }]
}];

// --- Sub-components ---

const DotGrid = () => <div className="absolute inset-0 dot-grid pointer-events-none z-0" aria-hidden="true" />;
const SectionHeadline = ({
  children,
  className
}: {
  children: React.ReactNode;
  className?: string;
}) => <h2 className={cn("text-condensed text-primary leading-[0.9]", className)}>
    {children}
  </h2>;
const MonospaceLabel = ({
  children,
  className
}: {
  children: React.ReactNode;
  className?: string;
}) => <span className={cn("text-monospace text-[12px] tracking-[0.2em]", className)}>
    {children}
  </span>;
const Button = ({
  children,
  variant = 'primary',
  className
}: {
  children: React.ReactNode;
  variant?: 'primary' | 'secondary';
  className?: string;
}) => <button className={cn("text-monospace font-bold uppercase transition-colors px-8 py-3 focus:outline-none", variant === 'primary' ? "bg-[#1B3499] text-white hover:bg-[#132670]" : "bg-transparent border border-primary text-primary hover:bg-primary/5", className)}>
    {children}
  </button>;

// --- Main Components ---

export const BreadMasterclass = () => {
  return <div className="relative min-h-screen bg-[#F5F0E8] overflow-x-hidden selection:bg-primary selection:text-white">
      {/* Navigation */}
      <nav className="fixed top-0 left-0 right-0 z-50 bg-[#F5F0E8] border-b border-[#E0D8CC] px-20 py-5 flex items-center justify-between">
        <div className="text-condensed text-[18px] text-primary tracking-tight">
          THE BREAD MASTERCLASS
        </div>

        <div className="hidden md:flex items-center gap-16">
          {NAV_LINKS.map(link => <a key={link.label} href={link.href} className="text-monospace text-[12px] text-[#2A2A2A] tracking-[0.2em] hover:text-primary transition-colors">
              {link.label}
            </a>)}
        </div>

        <Button className="py-2.5 px-6 text-[12px]">
          APPLY FOR THE COHORT
        </Button>
      </nav>

      {/* Hero Section */}
      <section className="relative h-screen flex pt-20">
        <DotGrid />

        <div className="w-1/2 flex flex-col justify-center pl-[100px] z-10">
          <MonospaceLabel className="text-primary mb-6">
            ONCE-A-YEAR MASTERCLASS
          </MonospaceLabel>
          <h1 className="text-condensed text-[120px] leading-[0.88] text-primary flex flex-col">
            <span>THE</span>
            <span>BREAD</span>
            <span>MASTER-</span>
            <span>CLASS</span>
          </h1>
          <div className="mt-10">
            <Button className="text-[14px]">
              APPLY FOR 2025 COHORT →
            </Button>
          </div>
        </div>

        <div className="w-1/2 relative flex items-center justify-center p-20 z-10">
          <div className="relative w-full h-full max-w-[500px] max-h-[600px]">
            {/* Photo 1: Sourdough close-up */}
            <motion.div initial={{
            rotate: -5,
            opacity: 0
          }} animate={{
            rotate: -3,
            opacity: 1
          }} transition={{
            delay: 0.2
          }} className="absolute top-0 left-0 w-[70%] z-20 shadow-2xl border-[4px] border-white">
              <img src="https://images.unsplash.com/photo-1585478259715-876acc5be8eb?auto=format&fit=crop&q=80&w=800" alt="Rustic sourdough close-up" className="w-full grayscale brightness-90" />
            </motion.div>

            {/* Photo 2: Hands shaping dough */}
            <motion.div initial={{
            rotate: 4,
            opacity: 0
          }} animate={{
            rotate: 2,
            opacity: 1
          }} transition={{
            delay: 0.4
          }} className="absolute bottom-0 right-0 w-[65%] z-30 shadow-2xl border-[4px] border-white">
              <img src="https://images.unsplash.com/photo-1549931319-a545dcf3bc73?auto=format&fit=crop&q=80&w=800" alt="Hands shaping dough" className="w-full grayscale contrast-125" />
            </motion.div>

            {/* Photo 3: Scored bread loaf */}
            <motion.div initial={{
            rotate: -2,
            opacity: 0
          }} animate={{
            rotate: -1.5,
            opacity: 1
          }} transition={{
            delay: 0.6
          }} className="absolute top-1/4 right-0 w-[55%] z-10 shadow-2xl border-[4px] border-white">
              <img src="https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&q=80&w=800" alt="Scored bread loaf" className="w-full grayscale" />
            </motion.div>

            {/* Stamp Seal */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-40 rotate-[15deg]">
              <div className="relative w-40 h-40 flex items-center justify-center">
                <svg className="w-full h-full animate-[spin_20s_linear_infinite]" viewBox="0 0 100 100">
                  <path id="circlePath" d="M 50, 50 m -37, 0 a 37,37 0 1,1 74,0 a 37,37 0 1,1 -74,0" fill="none" />
                  <text className="text-[9px] font-mono fill-primary uppercase tracking-widest">
                    <textPath xlinkHref="#circlePath">
                      EST. 2018 · THE BREAD MASTERCLASS · ARTISAN · EST. 2018 · THE BREAD MASTERCLASS · ARTISAN ·
                    </textPath>
                  </text>
                </svg>
                <div className="absolute inset-0 flex items-center justify-center">
                  <Wheat className="w-8 h-8 text-primary" />
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Ticker Bar */}
        <div className="absolute bottom-0 left-0 right-0 bg-primary h-20 overflow-hidden z-20 flex items-center">
          <div className="animate-marquee whitespace-nowrap flex items-center gap-8">
            {Array.from({
            length: 4
          }).map((_, i) => <span key={i} className="text-monospace text-white text-[14px] flex items-center gap-8">
                <span>12 SEATS</span>
                <span className="opacity-60">///</span>
                <span>HYDRATION MASTERY</span>
                <span className="opacity-60">///</span>
                <span>PRECISION FERMENTATION</span>
                <span className="opacity-60">///</span>
                <span>ONCE A YEAR</span>
                <span className="opacity-60">///</span>
              </span>)}
          </div>
        </div>
      </section>

      {/* Problem Section */}
      <section className="relative h-[80vh] bg-primary flex flex-col items-center justify-center text-center px-4 overflow-hidden">
        <h2 className="text-condensed text-white text-[108px] leading-[0.9] flex flex-col mb-10">
          <span>MOST BAKERS NEVER</span>
          <span>TRULY MASTER IT.</span>
        </h2>
        <div className="space-y-2">
          <p className="text-monospace text-white text-[16px] opacity-80 max-w-2xl">
            Bread is not about recipes. It is about understanding the living science beneath your hands.
          </p>
          <p className="text-monospace text-white text-[16px] opacity-80 max-w-2xl">
            We teach what culinary schools overlook.
          </p>
        </div>
      </section>

      {/* Curriculum Section */}
      <section id="curriculum" className="relative py-32 px-20">
        <DotGrid />
        <div className="relative z-10 max-w-7xl mx-auto">
          <div className="mb-20">
            <SectionHeadline className="text-[84px] mb-2">TECHNICAL CURRICULUM</SectionHeadline>
            <MonospaceLabel className="text-primary block mb-6 tracking-[0.3em]">/// 3-DAY IMMERSIVE BLUEPRINT</MonospaceLabel>
            <p className="text-[#2A2A2A] text-[16px] max-w-[520px] leading-relaxed">
              A comprehensive deep-dive into the thermodynamics and biology of bread. We bypass superficial techniques to focus on the fundamental chemistry that dictates every loaf.
            </p>
          </div>

          <div className="space-y-32">
            {CURRICULUM_DATA.map(day => <div key={day.number} className="relative group">
                {/* Watermark background */}
                <div className="absolute top-0 right-0 text-condensed text-white/40 text-[280px] pointer-events-none select-none -z-10 leading-none h-full flex items-start">
                  {day.number}
                </div>

                <div className="max-w-4xl">
                  <h3 className="text-condensed text-primary text-[40px] mb-4">{day.title}</h3>
                  <p className="text-[#2A2A2A] text-[15px] max-w-[600px] mb-12 opacity-80">
                    {day.description}
                  </p>

                  <div className="w-full overflow-hidden border border-[#E0D8CC]">
                    <div className="grid grid-cols-4 bg-[#F5F0E8] border-b border-[#E0D8CC] py-3 px-6">
                      <MonospaceLabel className="text-[11px] font-bold">TIME</MonospaceLabel>
                      <MonospaceLabel className="text-[11px] font-bold">MODULE</MonospaceLabel>
                      <MonospaceLabel className="text-[11px] font-bold text-center">HYDRATION %</MonospaceLabel>
                      <MonospaceLabel className="text-[11px] font-bold text-center">TEMP</MonospaceLabel>
                    </div>
                    <div className="divide-y divide-[#E0D8CC]">
                      {day.rows.map((row, idx) => <div key={idx} className={cn("grid grid-cols-4 px-6 py-4 items-center transition-colors", idx % 2 === 0 ? "bg-white" : "bg-[#EDE8DC]")}>
                          <div className="text-[14px] text-[#2A2A2A] font-medium">{row.time}</div>
                          <div className="text-[14px] text-[#2A2A2A]">{row.module}</div>
                          <div className="flex justify-center">
                            <span className="bg-primary text-white text-[12px] font-mono font-bold px-3 py-1 min-w-[50px] text-center">
                              {row.hydration}
                            </span>
                          </div>
                          <div className="flex justify-center">
                            <span className="bg-primary text-white text-[12px] font-mono font-bold px-3 py-1 min-w-[55px] text-center">
                              {row.temp}
                            </span>
                          </div>
                        </div>)}
                    </div>
                  </div>
                </div>
              </div>)}
          </div>
        </div>
      </section>

      {/* Instructor Section */}
      <section id="instructors" className="relative min-h-screen flex">
        <div className="w-[45%] h-full min-h-screen bg-black">
          <img src="https://images.unsplash.com/photo-1583394238182-6f3ad43267b1?auto=format&fit=crop&q=80&w=1200" alt="Chef Elena Russo" className="w-full h-full object-cover grayscale brightness-75 contrast-125" />
        </div>

        <div className="w-[55%] flex flex-col justify-center pl-20 pr-32 relative">
          <DotGrid />
          <div className="relative z-10">
            <MonospaceLabel className="text-primary mb-6 block">
              LEAD INSTRUCTOR // CHEF IN RESIDENCE
            </MonospaceLabel>
            <h2 className="text-condensed text-primary text-[84px] leading-[0.9] mb-12">
              CHEF ELENA<br />RUSSO
            </h2>

            <div className="space-y-6 max-w-lg mb-16">
              {["Elena Russo has spent two decades refining the ancestral art of fermentation in the foothills of Tuscany and the modern laboratories of Paris.", "Her philosophy centers on the living nature of bread—that every loaf is a negotiation between the baker, the environment, and the microbiome.", "In this masterclass, Elena moves beyond standard teaching to offer a rigorous, scientific approach to dough development and oven dynamics."].map((text, i) => <p key={i} className="text-[#2A2A2A] text-[16px] leading-relaxed border-l-[3px] border-primary pl-4">
                  {text}
                </p>)}
            </div>

            <div className="flex gap-4">
              {[{
              val: '18+',
              label: 'YEARS ACTIVE'
            }, {
              val: '12-YR',
              label: 'STARTER AGE'
            }, {
              val: 'GRAND',
              label: 'MASTER LEVEL'
            }].map((stat, i) => <div key={i} className="bg-white border-[1.5px] border-primary px-6 py-6 min-w-[140px]">
                  <div className="text-condensed text-primary text-[40px] leading-none mb-2">{stat.val}</div>
                  <MonospaceLabel className="text-[11px] text-[#2A2A2A] opacity-70 tracking-tighter">
                    {stat.label}
                  </MonospaceLabel>
                </div>)}
            </div>
          </div>
        </div>
      </section>

      {/* Application Form Section */}
      <section id="apply" className="relative py-32 bg-[#F5F0E8]">
        <DotGrid />
        <div className="relative z-10 max-w-[700px] mx-auto px-6">
          <div className="text-center mb-16">
            <h2 className="text-condensed text-primary text-[72px] leading-[0.9] mb-4">
              THE CRUCIBLE COHORT<br />APPLICATION
            </h2>
            <MonospaceLabel className="text-primary text-[12px]">
              | STRICT VALIDATION REQUIRED | // 12 SEATS REMAINING |
            </MonospaceLabel>
          </div>

          <form className="space-y-8" onSubmit={e => e.preventDefault()}>
            <div className="space-y-2">
              <MonospaceLabel className="text-[#555] text-[11px]">FULL NAME</MonospaceLabel>
              <input type="text" className="w-full bg-white border border-[#C8C0B0] px-4 py-3 text-[15px] focus:outline-none focus:border-primary transition-colors" placeholder="Johnathan Arbuthnot" />
            </div>

            <div className="space-y-2">
              <MonospaceLabel className="text-[#555] text-[11px]">EMAIL ADDRESS</MonospaceLabel>
              <input type="email" className="w-full bg-white border border-[#C8C0B0] px-4 py-3 text-[15px] focus:outline-none focus:border-primary transition-colors" placeholder="johnathan@bakery.com" />
            </div>

            <div className="space-y-2">
              <MonospaceLabel className="text-[#555] text-[11px]">CURRENT HYDRATION COMFORT LEVEL</MonospaceLabel>
              <select className="w-full bg-white border border-[#C8C0B0] px-4 py-3 text-[15px] focus:outline-none focus:border-primary transition-colors appearance-none">
                <option>Below 70% — Beginner</option>
                <option>70–75% — Intermediate</option>
                <option>75–80% — Advanced</option>
                <option>Above 80% — Expert</option>
              </select>
            </div>

            <div className="space-y-2">
              <MonospaceLabel className="text-[#555] text-[11px]">BAKING EXPERIENCE / PORTFOLIO LINK</MonospaceLabel>
              <textarea rows={6} className="w-full bg-white border border-[#C8C0B0] px-4 py-3 text-[15px] focus:outline-none focus:border-primary transition-colors resize-none" placeholder="Describe your baking background or paste a portfolio link..." />
            </div>

            <div className="pt-4">
              <Button className="w-full py-5 text-[16px]">
                SUBMIT APPLICATION →
              </Button>
              <div className="mt-6 text-center">
                <MonospaceLabel className="text-[11px] text-gray-500 lowercase opacity-60">
                  // Applications reviewed on a rolling basis. Limited seats. //
                </MonospaceLabel>
              </div>
            </div>
          </form>
        </div>
      </section>

      {/* Footer */}
      <footer className="bg-primary py-12 px-20 flex flex-col md:flex-row justify-between items-center text-white border-t border-white/10">
        <div className="text-condensed text-[15px] mb-4 md:mb-0">
          THE BREAD MASTERCLASS © 2025
        </div>
        <div className="flex gap-12">
          {['INSTAGRAM', 'TWITTER', 'JOURNAL'].map(social => <a key={social} href="#" className="text-monospace text-[11px] tracking-widest hover:opacity-70 transition-opacity">
              {social}
            </a>)}
        </div>
        <div className="text-monospace text-[11px] opacity-40 mt-4 md:mt-0">
          ALL RIGHTS RESERVED
        </div>
      </footer>
    </div>;
};
